import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Project, Client, User, IncomeRecord, UserProfile } from '../types';
import { supabase, isConfigured } from '../lib/supabase';

interface ToastState {
  message: string;
  type: 'success' | 'error';
}

interface AppContextType {
  // Visible Data (Filtered by Selected User if Admin)
  projects: Project[];
  setProjects: React.Dispatch<React.SetStateAction<Project[]>>;
  clients: Client[];
  setClients: React.Dispatch<React.SetStateAction<Client[]>>;
  incomeRecords: IncomeRecord[];
  setIncomeRecords: React.Dispatch<React.SetStateAction<IncomeRecord[]>>;

  // Master Data (Contains ALL data for Admin)
  allProjects: Project[];
  allClients: Client[];
  allIncomeRecords: IncomeRecord[];

  // Profiles Data (For Admin List)
  userProfiles: UserProfile[];

  user: User | null;
  setUser: React.Dispatch<React.SetStateAction<User | null>>;
  loading: boolean;
  refreshData: () => Promise<void>;
  toast: ToastState | null;
  showToast: (message: string, type?: 'success' | 'error') => void;
  hideToast: () => void;
  isAppLocked: boolean;
  setIsAppLocked: React.Dispatch<React.SetStateAction<boolean>>;
  appPin: string | null;
  setAppPin: (pin: string | null) => void;

  // Admin Specific
  adminSelectedUserId: string | null;
  setAdminSelectedUserId: React.Dispatch<React.SetStateAction<string | null>>;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);

  // Visible State (What components see)
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [incomeRecords, setIncomeRecords] = useState<IncomeRecord[]>([]);

  // Master State (All data cache for Admin)
  const [allProjects, setAllProjects] = useState<Project[]>([]);
  const [allClients, setAllClients] = useState<Client[]>([]);
  const [allIncomeRecords, setAllIncomeRecords] = useState<IncomeRecord[]>([]);

  // User Profiles
  const [userProfiles, setUserProfiles] = useState<UserProfile[]>([]);

  const [loading, setLoading] = useState(true);
  const [toast, setToast] = useState<ToastState | null>(null);

  // App Lock State
  const [isAppLocked, setIsAppLocked] = useState(false);
  const [appPin, setAppPinState] = useState<string | null>(null);

  // Admin Selection State
  const [adminSelectedUserId, setAdminSelectedUserId] = useState<string | null>(null);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'error') => {
    setToast({ message, type });
  }, []);

  const hideToast = useCallback(() => {
    setToast(null);
  }, []);

  const setAppPin = (pin: string | null) => {
    if (pin) {
        localStorage.setItem('manage_me_pin', pin);
    } else {
        localStorage.removeItem('manage_me_pin');
    }
    setAppPinState(pin);
  };

  const refreshData = async () => {
    if (!user || !isConfigured) return;
    try {
      const isAdmin = user.role === 'admin';

      // Base queries - fetch everything initially
      let projQuery = supabase.from('projects').select('*');
      let clientQuery = supabase.from('clients').select('*');
      let incomeQuery = supabase.from('income_records').select('*');

      // If NOT admin, filter at DB level for efficiency/security
      if (!isAdmin) {
        projQuery = projQuery.eq('userid', user.id);
        clientQuery = clientQuery.eq('userid', user.id);
        incomeQuery = incomeQuery.eq('userid', user.id);
      }

      const [projRes, clientRes, incomeRes] = await Promise.all([
        projQuery.order('createdat', { ascending: false }),
        clientQuery.order('name', { ascending: true }),
        incomeQuery.order('date', { ascending: false })
      ]);

      if (projRes.error) console.warn(`Project load error: ${projRes.error.message}`);
      if (clientRes.error) console.warn(`Client load error: ${clientRes.error.message}`);
      if (incomeRes.error) console.warn(`Income load error: ${incomeRes.error.message}`);

      const pData = projRes.data as Project[] || [];
      const cData = clientRes.data as Client[] || [];
      const iData = incomeRes.data as IncomeRecord[] || [];

      if (isAdmin) {
        // Store everything in Master State
        setAllProjects(pData);
        setAllClients(cData);
        setAllIncomeRecords(iData);

        // Fetch User Profiles for Admin List
        const { data: profiles, error: profError } = await supabase.from('profiles').select('*');
        if (!profError && profiles) {
            setUserProfiles(profiles as UserProfile[]);
        }

        // Filter Visible State based on Selection
        if (adminSelectedUserId) {
            setProjects(pData.filter(p => p.userid === adminSelectedUserId));
            setClients(cData.filter(c => c.userid === adminSelectedUserId));
            setIncomeRecords(iData.filter(i => i.userid === adminSelectedUserId));
        } else {
            // If no user selected, show NOTHING in the main views (forces selection from list)
            setProjects([]);
            setClients([]);
            setIncomeRecords([]);
        }
      } else {
        // Normal User: Visible = All fetched
        setProjects(pData);
        setClients(cData);
        setIncomeRecords(iData);
      }

    } catch (error: any) {
      showToast(`কানেকশন এরর: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  // Effect to re-filter data when Admin selection changes without re-fetching
  useEffect(() => {
    if (user?.role === 'admin') {
        if (adminSelectedUserId) {
            setProjects(allProjects.filter(p => p.userid === adminSelectedUserId));
            setClients(allClients.filter(c => c.userid === adminSelectedUserId));
            setIncomeRecords(allIncomeRecords.filter(i => i.userid === adminSelectedUserId));
        } else {
            setProjects([]);
            setClients([]);
            setIncomeRecords([]);
        }
    }
  }, [adminSelectedUserId, allProjects, allClients, allIncomeRecords, user]);

  // Helper to sync user state with DB profile
  const syncUserWithProfile = async (sessionUser: any) => {
      if (!sessionUser) return null;

      try {
          const metadata = sessionUser.user_metadata;

          // Fetch fresh profile data from DB (Source of Truth)
          // Using maybeSingle() to handle 0 rows gracefully
          const { data: profile } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', sessionUser.id)
            .maybeSingle();

          // Prioritize DB profile over auth metadata for name/avatar
          return {
              id: sessionUser.id,
              email: sessionUser.email || '',
              name: profile?.name || metadata?.name || 'User',
              phone: metadata?.phone || '',
              occupation: metadata?.occupation || '',
              avatar_url: profile?.avatar_url || metadata?.avatar_url || '',
              language: metadata?.language || 'bn',
              currency: metadata?.currency || '৳',
              role: metadata?.role || 'user'
          };
      } catch (e) {
          console.error("Profile sync error", e);
          // Fallback return
          return {
              id: sessionUser.id,
              email: sessionUser.email || '',
              name: sessionUser.user_metadata?.name || 'User',
              role: 'user',
              language: 'bn',
              currency: '৳',
              avatar_url: ''
          } as User;
      }
  };

  useEffect(() => {
    let mounted = true;

    // Check local storage for PIN
    const savedPin = localStorage.getItem('manage_me_pin');
    if (savedPin) {
        setAppPinState(savedPin);
        setIsAppLocked(true); 
    }

    if (!isConfigured) {
      setLoading(false);
      return;
    }

    const initSession = async () => {
      try {
        // Add timeout to prevent infinite loading if getSession hangs
        const sessionPromise = supabase.auth.getSession();
        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error('Session timeout')), 7000)
        );

        const { data: { session }, error } = await Promise.race([sessionPromise, timeoutPromise]) as any;

        if (error) {
            console.warn("Session Init Warning:", error);
        }

        if (session?.user && mounted) {
          const userData = await syncUserWithProfile(session.user);
          if (mounted) setUser(userData);
        }
      } catch (err) {
        console.error("Session Init Error:", err);
      } finally {
        if (mounted) setLoading(false);
      }
    };

    initSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (session?.user) {
        if (mounted) {
            // Re-sync on auth change to ensure we have latest role/profile
            const userData = await syncUserWithProfile(session.user);
            setUser(userData);
        }
      } else {
        if (mounted) {
            setUser(null);
            setProjects([]);
            setClients([]);
            setIncomeRecords([]);
            setAllProjects([]);
            setAllClients([]);
            setAllIncomeRecords([]);
            setUserProfiles([]);
            setAdminSelectedUserId(null);
        }
      }
      // Ensure loading is cleared on auth state change (backup safety)
      if (mounted) setLoading(false);
    });

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, [showToast]);

  useEffect(() => {
    if (user) {
      refreshData();
    }
  }, [user]);

  return (
    <AppContext.Provider value={{ 
      projects, setProjects, clients, setClients, 
      incomeRecords, setIncomeRecords,
      allProjects, allClients, allIncomeRecords,
      userProfiles,
      user, setUser, loading, refreshData,
      toast, showToast, hideToast,
      isAppLocked, setIsAppLocked,
      appPin, setAppPin,
      adminSelectedUserId, setAdminSelectedUserId
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useAppContext = () => {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error('useAppContext must be used within an AppProvider');
  }
  return context;
};

export type ProjectStatus = 'Pending' | 'In Progress' | 'Completed';
export type ProjectType = 'NasheedSong' | 'Ads' | 'Waz';

export interface Project {
  id: string;
  name: string;
  clientname: string;
  type: ProjectType;
  totalamount: number;
  paidamount: number;
  dueamount: number;
  status: ProjectStatus;
  deadline?: string | null;
  createdat: string;
  notes?: string;
  userid: string;
}

export interface Client {
  id: string;
  name: string;
  contact: string;
  totalprojects: number;
  totalearnings: number;
  userid: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  date: string;
  notes: string;
  userid: string;
}

export interface IncomeRecord {
  id: string;
  projectid: string;
  projectname: string;
  clientname: string;
  amount: number;
  date: string;
  method: string;
  userid: string;
}

export interface User {
  id: string;
  email: string;
  name: string;
  phone?: string;
  occupation?: string;
  avatar_url?: string;
  language: 'bn' | 'en';
  currency: string;
  role: 'user' | 'admin';
}

export interface UserProfile {
  id: string;
  name: string | null;
  email: string | null;
  avatar_url: string | null;
}

import React, { useState, useRef } from 'react';
import { User as UserIcon, Bell, Shield, Palette, Globe, Save, CheckCircle2, Loader2, Camera, UploadCloud, AlertCircle, Lock, Key } from 'lucide-react';
import { APP_NAME } from '../constants';
import { useAppContext } from '../context/AppContext';
import { supabase } from '../lib/supabase';
import { AppLock } from '../components/AppLock';

export const Settings: React.FC = () => {
  const { user, setUser, showToast, appPin, setAppPin } = useAppContext();
  const [formData, setFormData] = useState({
    name: user?.name || '',
    email: user?.email || '',
    phone: user?.phone || '',
    occupation: user?.occupation || '',
    language: user?.language || 'bn',
    currency: user?.currency || '৳'
  });
  const [isSaving, setIsSaving] = useState(false);
  const [isUploading, setIsUploading] = useState(false);

  // Security State
  const [newPassword, setNewPassword] = useState('');
  const [isChangingPass, setIsChangingPass] = useState(false);

  // 'setup' means setting a new pin, 'disable' means verifying pin to turn it off
  const [pinAction, setPinAction] = useState<'setup' | 'disable' | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0 || !user) return;

    const file = e.target.files[0];
    const fileExt = file.name.split('.').pop();
    const fileName = `${user.id}/${Date.now()}.${fileExt}`;
    const filePath = fileName;

    setIsUploading(true);

    try {
      const { error: uploadError } = await supabase.storage
        .from('avatars')
        .upload(filePath, file, { upsert: true });

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from('avatars')
        .getPublicUrl(filePath);

      // Update Auth Metadata
      const { error: authError } = await supabase.auth.updateUser({
        data: { avatar_url: publicUrl }
      });

      if (authError) throw authError;

      // Update Profiles Table (Source of Truth)
      const { error: profileError } = await supabase
        .from('profiles')
        .update({ avatar_url: publicUrl })
        .eq('id', user.id);

      if (profileError) console.error("Profile update failed", profileError);

      setUser(prev => prev ? ({ ...prev, avatar_url: publicUrl }) : null);
      showToast('প্রোফাইল ছবি আপডেট হয়েছে!', 'success');

    } catch (error: any) {
      console.error(error);
      showToast('ছবি আপলোড করতে সমস্যা হয়েছে', 'error');
    } finally {
      setIsUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleSave = async () => {
    if (!user) return;
    setIsSaving(true);

    try {
      // 1. Update Auth Metadata
      const { data, error } = await supabase.auth.updateUser({
        data: {
          name: formData.name,
          phone: formData.phone,
          occupation: formData.occupation,
          language: formData.language,
          currency: formData.currency
        }
      });

      if (error) throw error;

      // 2. Update Profiles Table (Source of Truth)
      const { error: profileError } = await supabase
        .from('profiles')
        .update({ 
            name: formData.name,
            // Add other fields to profiles if your schema supports them
        })
        .eq('id', user.id);

      if (profileError) console.error("Profile update failed", profileError);

      setUser(prev => prev ? ({
        ...prev,
        name: formData.name,
        phone: formData.phone,
        occupation: formData.occupation,
        language: formData.language as 'bn' | 'en',
        currency: formData.currency
      }) : null);

      showToast('সেটিংস সফলভাবে সেভ হয়েছে', 'success');
    } catch (err: any) {
      showToast(`সেভ করতে সমস্যা হয়েছে: ${err.message}`, 'error');
    } finally {
      setIsSaving(false);
    }
  };

  const handleChangePassword = async () => {
    if (!newPassword || newPassword.length < 6) {
        showToast('পাসওয়ার্ড অন্তত ৬ অক্ষরের হতে হবে', 'error');
        return;
    }
    setIsChangingPass(true);
    try {
        const { error } = await supabase.auth.updateUser({ password: newPassword });
        if (error) throw error;
        showToast('পাসওয়ার্ড পরিবর্তন সফল হয়েছে', 'success');
        setNewPassword('');
    } catch (err: any) {
        showToast(`ভুল: ${err.message}`, 'error');
    } finally {
        setIsChangingPass(false);
    }
  };

  const handlePinToggle = () => {
      if (appPin) {
          // If PIN exists, we want to disable it. 
          // Open AppLock in 'unlock' mode to verify current PIN first.
          setPinAction('disable');
      } else {
          // If no PIN, we want to setup a new one.
          setPinAction('setup');
      }
  };

  const handlePinSuccess = (pin: string) => {
      if (pinAction === 'setup') {
          setAppPin(pin);
          showToast('অ্যাপ লক চালু করা হয়েছে!', 'success');
      } else if (pinAction === 'disable') {
          setAppPin(null);
          showToast('অ্যাপ লক বন্ধ করা হয়েছে', 'success');
      }
      setPinAction(null);
  };

  if (!user) return null;

  return (
    <div className="space-y-6 pb-20">
      <div>
        <h1 className="text-2xl font-bold text-slate-800">সেটিংস</h1>
        <p className="text-slate-500">প্রোফাইল এবং সিকিউরিটি কনফিগারেশন</p>
      </div>

      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        {/* Profile Header */}
        <div className="p-6 border-b flex items-center gap-5 bg-slate-50/50">
          <div className="relative group">
            <div className="w-20 h-20 rounded-full overflow-hidden border-4 border-white shadow-lg bg-indigo-100 flex items-center justify-center relative">
               {user.avatar_url ? (
                 <img src={user.avatar_url} alt="Profile" className="w-full h-full object-cover" />
               ) : (
                 <span className="text-indigo-600 text-3xl font-bold">{formData.name ? formData.name.charAt(0) : 'U'}</span>
               )}
               {isUploading && (
                 <div className="absolute inset-0 bg-black/60 flex items-center justify-center z-10">
                   <Loader2 className="animate-spin text-white" size={24} />
                 </div>
               )}
            </div>
            <button 
              disabled={isUploading}
              onClick={() => fileInputRef.current?.click()}
              className="absolute bottom-0 right-0 bg-indigo-600 text-white p-2 rounded-full shadow-md hover:bg-indigo-700 active:scale-90 transition-transform cursor-pointer z-20"
            >
              <Camera size={14} />
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
          </div>
          <div>
            <h3 className="text-lg font-bold text-slate-800">{formData.name || 'ইউজার'}</h3>
            <p className="text-slate-500 text-xs font-medium">{formData.occupation || 'পেশা যুক্ত করা হয়নি'}</p>
          </div>
        </div>

        <div className="p-6 space-y-8">
          {/* General Settings */}
          <div className="space-y-4">
             <div className="grid grid-cols-1 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">পূর্ণ নাম</label>
                  <input type="text" name="name" value={formData.name} onChange={handleChange} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 text-slate-900 font-medium" />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">পেশা</label>
                  <input type="text" name="occupation" value={formData.occupation} onChange={handleChange} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 text-slate-900 font-medium" placeholder="যেমন: সাউন্ড ইঞ্জিনিয়ার" />
                </div>
                <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">মুদ্রা (Currency)</label>
                    <select name="currency" value={formData.currency} onChange={handleChange} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 text-slate-900 font-medium cursor-pointer">
                        <option value="৳">টাকা (৳)</option>
                        <option value="$">ইউএস ডলার ($)</option>
                        <option value="₹">ইন্ডিয়ান রুপি (₹)</option>
                        <option value="€">ইউরো (€)</option>
                        <option value="£">পাউন্ড (£)</option>
                        <option value="SAR">সৌদি রিয়াল (SAR)</option>
                        <option value="AED">আমিরাতি দিরহাম (AED)</option>
                        <option value="MYR">মালয়েশিয়ান রিঙ্গিত (MYR)</option>
                    </select>
                </div>
             </div>
             <button onClick={handleSave} disabled={isSaving} className="w-full flex justify-center items-center gap-2 px-6 py-3.5 rounded-xl font-bold bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 transition-all shadow-lg shadow-indigo-100 mt-2">
                {isSaving ? <Loader2 size={18} className="animate-spin" /> : <Save size={18} />}
                {isSaving ? 'সেভ হচ্ছে...' : 'পরিবর্তন সেভ করুন'}
             </button>
          </div>

          {/* Security Section */}
          <div className="pt-6 border-t border-slate-100">
             <h4 className="font-bold text-slate-800 mb-4 flex items-center gap-2 text-sm">
               <Shield size={16} className="text-indigo-600" />
               সিকিউরিটি
             </h4>

             {/* App Lock */}
             <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 mb-6 flex items-center justify-between">
                 <div className="flex items-center gap-3">
                     <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${appPin ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-200 text-slate-500'}`}>
                         <Lock size={20} />
                     </div>
                     <div>
                         <p className="font-bold text-slate-800 text-sm">অ্যাপ লক</p>
                         <p className="text-xs text-slate-500">{appPin ? 'পিন কোড চালু আছে' : 'পিন কোড দিয়ে অ্যাপ লক করুন'}</p>
                     </div>
                 </div>
                 <button 
                    onClick={handlePinToggle}
                    className={`relative w-12 h-6 rounded-full transition-colors duration-300 ${appPin ? 'bg-indigo-600' : 'bg-slate-300'}`}
                 >
                     <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-transform duration-300 shadow-sm ${appPin ? 'left-7' : 'left-1'}`}></div>
                 </button>
             </div>

             {/* Change Password */}
             <div className="space-y-3">
                <label className="block text-sm font-semibold text-slate-700">পাসওয়ার্ড পরিবর্তন</label>
                <div className="flex gap-2">
                    <div className="relative flex-1">
                        <Key size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="password" 
                            placeholder="নতুন পাসওয়ার্ড দিন..." 
                            value={newPassword}
                            onChange={(e) => setNewPassword(e.target.value)}
                            className="w-full pl-9 pr-4 py-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 text-sm font-medium"
                        />
                    </div>
                    <button 
                        onClick={handleChangePassword}
                        disabled={!newPassword || isChangingPass}
