        <div className="p-6 space-y-8">
          {/* General Settings */}
          <div className="space-y-4">
             <div className="grid grid-cols-1 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">পূর্ণ নাম</label>
