import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { Project, Client, User, IncomeRecord, UserProfile } from '../types';
import { supabase, isConfigured } from '../lib/supabase';

interface ToastState {
  message: string;
  type: 'success' | 'error';
}

interface AppContextType {
  // Visible Data (Filtered by Selected User if Admin)
  projects: Project[];
  setProjects: React.Dispatch<React.SetStateAction<Project[]>>;
  clients: Client[];
  setClients: React.Dispatch<React.SetStateAction<Client[]>>;
  incomeRecords: IncomeRecord[];
  setIncomeRecords: React.Dispatch<React.SetStateAction<IncomeRecord[]>>;

  // Master Data (Contains ALL data for Admin)
  allProjects: Project[];
  allClients: Client[];
  allIncomeRecords: IncomeRecord[];

  // Profiles Data (For Admin List)
  userProfiles: UserProfile[];

  user: User | null;
  setUser: React.Dispatch<React.SetStateAction<User | null>>;
  loading: boolean;
  refreshData: () => Promise<void>;
  toast: ToastState | null;
  showToast: (message: string, type?: 'success' | 'error') => void;
  hideToast: () => void;
  isAppLocked: boolean;
  setIsAppLocked: React.Dispatch<React.SetStateAction<boolean>>;
  appPin: string | null;
  setAppPin: (pin: string | null) => void;

  // Admin Specific
  adminSelectedUserId: string | null;
  setAdminSelectedUserId: React.Dispatch<React.SetStateAction<string | null>>;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);

  // Visible State (What components see)
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [incomeRecords, setIncomeRecords] = useState<IncomeRecord[]>([]);

  // Master State (All data cache for Admin)
  const [allProjects, setAllProjects] = useState<Project[]>([]);
  const [allClients, setAllClients] = useState<Client[]>([]);
  const [allIncomeRecords, setAllIncomeRecords] = useState<IncomeRecord[]>([]);

  // User Profiles
  const [userProfiles, setUserProfiles] = useState<UserProfile[]>([]);

  const [loading, setLoading] = useState(true);
  const [toast, setToast] = useState<ToastState | null>(null);

  // App Lock State
  const [isAppLocked, setIsAppLocked] = useState(false);
  const [appPin, setAppPinState] = useState<string | null>(null);

  // Admin Selection State
  const [adminSelectedUserId, setAdminSelectedUserId] = useState<string | null>(null);

  // Performance optimization: Prevent multiple simultaneous refreshes
  const isFetchingRef = useRef(false);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'error') => {
    setToast({ message, type });
  }, []);

  const hideToast = useCallback(() => {
    setToast(null);
  }, []);

  const setAppPin = (pin: string | null) => {
    if (pin) {
        localStorage.setItem('manage_me_pin', pin);
    } else {
        localStorage.removeItem('manage_me_pin');
    }
    setAppPinState(pin);
  };

  const refreshData = async () => {
    if (!user || !isConfigured) return;

    // If already fetching, ignore this request to save bandwidth
    if (isFetchingRef.current) return;
    isFetchingRef.current = true;

    try {
      const isAdmin = user.role === 'admin';

      // Base queries - fetch everything initially
      let projQuery = supabase.from('projects').select('*');
      let clientQuery = supabase.from('clients').select('*');
      let incomeQuery = supabase.from('income_records').select('*');

      // If NOT admin, filter at DB level for efficiency/security
      if (!isAdmin) {
        projQuery = projQuery.eq('userid', user.id);
        clientQuery = clientQuery.eq('userid', user.id);
        incomeQuery = incomeQuery.eq('userid', user.id);
      }

      const [projRes, clientRes, incomeRes] = await Promise.all([
        projQuery.order('createdat', { ascending: false }),
        clientQuery.order('name', { ascending: true }),
        incomeQuery.order('date', { ascending: false })
      ]);

      if (projRes.error) console.warn(`Project load error: ${projRes.error.message}`);
      if (clientRes.error) console.warn(`Client load error: ${clientRes.error.message}`);
      if (incomeRes.error) console.warn(`Income load error: ${incomeRes.error.message}`);

      const pData = projRes.data as Project[] || [];
      const cData = clientRes.data as Client[] || [];
      const iData = incomeRes.data as IncomeRecord[] || [];

      if (isAdmin) {
        // Store everything in Master State
        setAllProjects(pData);
        setAllClients(cData);
        setAllIncomeRecords(iData);

        // Fetch User Profiles for Admin List
        const { data: profiles, error: profError } = await supabase.from('profiles').select('*');
        if (!profError && profiles) {
            setUserProfiles(profiles as UserProfile[]);
        }

        // Filter Visible State based on Selection
        if (adminSelectedUserId) {
            setProjects(pData.filter(p => p.userid === adminSelectedUserId));
            setClients(cData.filter(c => c.userid === adminSelectedUserId));
            setIncomeRecords(iData.filter(i => i.userid === adminSelectedUserId));
        } else {
            // If no user selected, show NOTHING in the main views (forces selection from list)
            setProjects([]);
            setClients([]);
            setIncomeRecords([]);
        }
      } else {
        // Normal User: Visible = All fetched
        setProjects(pData);
        setClients(cData);
        setIncomeRecords(iData);
      }

    } catch (error: any) {
      showToast(`কানেকশন এরর: ${error.message}`);
    } finally {
      setLoading(false);
      isFetchingRef.current = false;
    }
  };

  // Effect to re-filter data when Admin selection changes without re-fetching
  useEffect(() => {
    if (user?.role === 'admin') {
        if (adminSelectedUserId) {
            setProjects(allProjects.filter(p => p.userid === adminSelectedUserId));
            setClients(allClients.filter(c => c.userid === adminSelectedUserId));
            setIncomeRecords(allIncomeRecords.filter(i => i.userid === adminSelectedUserId));
        } else {
            setProjects([]);
            setClients([]);
            setIncomeRecords([]);
        }
    }
  }, [adminSelectedUserId, allProjects, allClients, allIncomeRecords, user]);

  // Helper to sync user state with DB profile
  const syncUserWithProfile = async (sessionUser: any) => {
      if (!sessionUser) return null;

      try {
          const metadata = sessionUser.user_metadata;

          // Fetch fresh profile data from DB (Source of Truth)
          // Using maybeSingle() to handle 0 rows gracefully
          const { data: profile } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', sessionUser.id)
            .maybeSingle();

          // Prioritize DB profile over auth metadata for name/avatar
          return {
              id: sessionUser.id,
              email: sessionUser.email || '',
              name: profile?.name || metadata?.name || 'User',
              phone: metadata?.phone || '',
              occupation: metadata?.occupation || '',
              avatar_url: profile?.avatar_url || metadata?.avatar_url || '',
              language: metadata?.language || 'bn',
              currency: metadata?.currency || '৳',
              role: metadata?.role || 'user'
          };
      } catch (e) {
          console.error("Profile sync error", e);
          // Fallback return
          return {
              id: sessionUser.id,
              email: sessionUser.email || '',
              name: sessionUser.user_metadata?.name || 'User',
              role: 'user',
              language: 'bn',
              currency: '৳',
              avatar_url: ''
          } as User;
      }
  };

  useEffect(() => {
    let mounted = true;

    // Check local storage for PIN
    const savedPin = localStorage.getItem('manage_me_pin');
    if (savedPin) {
        setAppPinState(savedPin);
        setIsAppLocked(true); 
    }

    if (!isConfigured) {
      setLoading(false);
      return;
    }

    const initSession = async () => {
      try {
        // Add timeout to prevent infinite loading if getSession hangs
        const sessionPromise = supabase.auth.getSession();
        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error('Session timeout')), 7000)
        );

        const { data: { session }, error } = await Promise.race([sessionPromise, timeoutPromise]) as any;

        if (error) {
            console.warn("Session Init Warning:", error);
        }

        if (session?.user && mounted) {
          const userData = await syncUserWithProfile(session.user);
          if (mounted) setUser(userData);
        }
      } catch (err) {
        console.error("Session Init Error:", err);
      } finally {
        if (mounted) setLoading(false);
      }
    };

    initSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (session?.user) {
        if (mounted) {
            // Re-sync on auth change to ensure we have latest role/profile
            const userData = await syncUserWithProfile(session.user);
            setUser(userData);
        }
      } else {
        if (mounted) {
            setUser(null);
            setProjects([]);
            setClients([]);
            setIncomeRecords([]);
            setAllProjects([]);
            setAllClients([]);
            setAllIncomeRecords([]);
            setUserProfiles([]);
            setAdminSelectedUserId(null);
        }
      }
      // Ensure loading is cleared on auth state change (backup safety)
      if (mounted) setLoading(false);
    });

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, [showToast]);

  useEffect(() => {
    if (user) {
      refreshData();
    }
  }, [user]);

  return (
    <AppContext.Provider value={{ 
      projects, setProjects, clients, setClients, 
      incomeRecords, setIncomeRecords,
      allProjects, allClients, allIncomeRecords,
      userProfiles,
      user, setUser, loading, refreshData,
      toast, showToast, hideToast,
      isAppLocked, setIsAppLocked,
      appPin, setAppPin,
      adminSelectedUserId, setAdminSelectedUserId
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useAppContext = () => {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error('useAppContext must be used within an AppProvider');
  }
  return context;
};

import React, { useState, useRef } from 'react';
import { User as UserIcon, Bell, Shield, Palette, Globe, Save, CheckCircle2, Loader2, Camera, UploadCloud, AlertCircle, Lock, Key } from 'lucide-react';
import { APP_NAME } from '../constants';
import { useAppContext } from '../context/AppContext';
import { supabase } from '../lib/supabase';
import { AppLock } from '../components/AppLock';

export const Settings: React.FC = () => {
  const { user, setUser, showToast, appPin, setAppPin } = useAppContext();
  const [formData, setFormData] = useState({
    name: user?.name || '',
    email: user?.email || '',
    phone: user?.phone || '',
    occupation: user?.occupation || '',
    language: user?.language || 'bn',
    currency: user?.currency || '৳'
  });
  const [isSaving, setIsSaving] = useState(false);
  const [isUploading, setIsUploading] = useState(false);

  // Security State
  const [newPassword, setNewPassword] = useState('');
  const [isChangingPass, setIsChangingPass] = useState(false);

  // 'setup' means setting a new pin, 'disable' means verifying pin to turn it off
  const [pinAction, setPinAction] = useState<'setup' | 'disable' | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0 || !user) return;

    const file = e.target.files[0];
    const fileExt = file.name.split('.').pop();
    const fileName = `${user.id}/${Date.now()}.${fileExt}`;
    const filePath = fileName;

    setIsUploading(true);

    try {
      const { error: uploadError } = await supabase.storage
        .from('avatars')
        .upload(filePath, file, { upsert: true });

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from('avatars')
        .getPublicUrl(filePath);

      // Update Auth Metadata
      const { error: authError } = await supabase.auth.updateUser({
        data: { avatar_url: publicUrl }
      });

      if (authError) throw authError;

      // Update Profiles Table (Source of Truth)
      const { error: profileError } = await supabase
        .from('profiles')
        .update({ avatar_url: publicUrl })
        .eq('id', user.id);

      if (profileError) console.error("Profile update failed", profileError);

      setUser(prev => prev ? ({ ...prev, avatar_url: publicUrl }) : null);
      showToast('প্রোফাইল ছবি আপডেট হয়েছে!', 'success');

    } catch (error: any) {
      console.error(error);
      showToast('ছবি আপলোড করতে সমস্যা হয়েছে', 'error');
    } finally {
      setIsUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleSave = async () => {
    if (!user) return;
    setIsSaving(true);

    try {
      // 1. Force Refresh Session (Fixes stale token/hanging issues)
      const { error: refreshError } = await supabase.auth.refreshSession();
      if (refreshError) console.warn("Session refresh warning:", refreshError);

      // 2. Prepare Updates with longer timeout (20s)
      const timeoutPromise = new Promise((_, reject) => 
          setTimeout(() => reject(new Error('নেটওয়ার্ক সমস্যা (Timeout)')), 20000)
      );

      const updatePromise = supabase.auth.updateUser({
        data: {
          name: formData.name,
          phone: formData.phone,
          occupation: formData.occupation,
          language: formData.language,
          currency: formData.currency
        }
      });

      // Race condition: wait for update or timeout
      const { error } = await Promise.race([updatePromise, timeoutPromise]) as any;

      if (error) throw error;

      // 3. Update Profiles Table in background (Don't block UI)
      supabase.from('profiles')
        .update({ name: formData.name })
        .eq('id', user.id)
        .then(({ error }) => {
            if (error) console.warn("Profile table update failed silently", error);
        });

      // 4. Update Local State immediately
      setUser(prev => prev ? ({
        ...prev,
        name: formData.name,
        phone: formData.phone,
        occupation: formData.occupation,
        language: formData.language as 'bn' | 'en',
        currency: formData.currency
      }) : null);

      showToast('সেটিংস সফলভাবে সেভ হয়েছে', 'success');
    } catch (err: any) {
      console.error("Save Error:", err);
      showToast(`সেভ হয়নি: ${err.message || 'Unknown error'}`, 'error');
    } finally {
      setIsSaving(false);
    }
  };

  const handleChangePassword = async () => {
    if (!newPassword || newPassword.length < 6) {
        showToast('পাসওয়ার্ড অন্তত ৬ অক্ষরের হতে হবে', 'error');
        return;
    }
    setIsChangingPass(true);
    try {
        const { error } = await supabase.auth.updateUser({ password: newPassword });
        if (error) throw error;
        showToast('পাসওয়ার্ড পরিবর্তন সফল হয়েছে', 'success');
        setNewPassword('');
    } catch (err: any) {
        showToast(`ভুল: ${err.message}`, 'error');
    } finally {
        setIsChangingPass(false);
    }
  };

  const handlePinToggle = () => {
      if (appPin) {
          // If PIN exists, we want to disable it. 
          // Open AppLock in 'unlock' mode to verify current PIN first.
          setPinAction('disable');
      } else {
          // If no PIN, we want to setup a new one.
          setPinAction('setup');
      }
  };

  const handlePinSuccess = (pin: string) => {
      if (pinAction === 'setup') {
          setAppPin(pin);
          showToast('অ্যাপ লক চালু করা হয়েছে!', 'success');
      } else if (pinAction === 'disable') {
          setAppPin(null);
          showToast('অ্যাপ লক বন্ধ করা হয়েছে', 'success');
      }
      setPinAction(null);
  };

  if (!user) return null;

  return (
    <div className="space-y-6 pb-20">
      <div>
        <h1 className="text-2xl font-bold text-slate-800">সেটিংস</h1>
        <p className="text-slate-500">প্রোফাইল এবং সিকিউরিটি কনফিগারেশন</p>
      </div>

      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        {/* Profile Header */}
        <div className="p-6 border-b flex items-center gap-5 bg-slate-50/50">
          <div className="relative group">
            <div className="w-20 h-20 rounded-full overflow-hidden border-4 border-white shadow-lg bg-indigo-100 flex items-center justify-center relative">
               {user.avatar_url ? (
                 <img src={user.avatar_url} alt="Profile" className="w-full h-full object-cover" />
               ) : (
                 <span className="text-indigo-600 text-3xl font-bold">{formData.name ? formData.name.charAt(0) : 'U'}</span>
               )}
               {isUploading && (
                 <div className="absolute inset-0 bg-black/60 flex items-center justify-center z-10">
                   <Loader2 className="animate-spin text-white" size={24} />
                 </div>
               )}
            </div>
            <button 
              disabled={isUploading}
              onClick={() => fileInputRef.current?.click()}
              className="absolute bottom-0 right-0 bg-indigo-600 text-white p-2 rounded-full shadow-md hover:bg-indigo-700 active:scale-90 transition-transform cursor-pointer z-20"
            >
              <Camera size={14} />
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
          </div>
          <div>
            <h3 className="text-lg font-bold text-slate-800">{formData.name || 'ইউজার'}</h3>
            <p className="text-slate-500 text-xs font-medium">{formData.occupation || 'পেশা যুক্ত করা হয়নি'}</p>
          </div>
        </div>

        <div className="p-6 space-y-8">
          {/* General Settings */}
          <div className="space-y-4">
             <div className="grid grid-cols-1 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">পূর্ণ নাম</label>
                  <input type="text" name="name" value={formData.name} onChange={handleChange} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 text-slate-900 font-medium" />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">পেশা</label>
                  <input type="text" name="occupation" value={formData.occupation} onChange={handleChange} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 text-slate-900 font-medium" placeholder="যেমন: সাউন্ড ইঞ্জিনিয়ার" />
                </div>
                <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">মুদ্রা (Currency)</label>
                    <select name="currency" value={formData.currency} onChange={handleChange} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 text-slate-900 font-medium cursor-pointer">
                        <option value="৳">টাকা (৳)</option>
                        <option value="$">ইউএস ডলার ($)</option>
                        <option value="₹">ইন্ডিয়ান রুপি (₹)</option>
                        <option value="€">ইউরো (€)</option>
                        <option value="£">পাউন্ড (£)</option>
                        <option value="SAR">সৌদি রিয়াল (SAR)</option>
                        <option value="AED">আমিরাতি দিরহাম (AED)</option>
                        <option value="MYR">মালয়েশিয়ান রিঙ্গিত (MYR)</option>
                    </select>
                </div>
             </div>
             <button onClick={handleSave} disabled={isSaving} className="w-full flex justify-center items-center gap-2 px-6 py-3.5 rounded-xl font-bold bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 transition-all shadow-lg shadow-indigo-100 mt-2">
                {isSaving ? <Loader2 size={18} className="animate-spin" /> : <Save size={18} />}
                {isSaving ? 'সেভ হচ্ছে...' : 'পরিবর্তন সেভ করুন'}
             </button>
          </div>

          {/* Security Section */}
          <div className="pt-6 border-t border-slate-100">
             <h4 className="font-bold text-slate-800 mb-4 flex items-center gap-2 text-sm">
               <Shield size={16} className="text-indigo-600" />
               সিকিউরিটি
             </h4>

             {/* App Lock */}
             <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 mb-6 flex items-center justify-between">
                 <div className="flex items-center gap-3">
                     <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${appPin ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-200 text-slate-500'}`}>
                         <Lock size={20} />
                     </div>
                     <div>
                         <p className="font-bold text-slate-800 text-sm">অ্যাপ লক</p>
                         <p className="text-xs text-slate-500">{appPin ? 'পিন কোড চালু আছে' : 'পিন কোড দিয়ে অ্যাপ লক করুন'}</p>
                     </div>
                 </div>
                 <button 
                    onClick={handlePinToggle}
                    className={`relative w-12 h-6 rounded-full transition-colors duration-300 ${appPin ? 'bg-indigo-600' : 'bg-slate-300'}`}
                 >
                     <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-transform duration-300 shadow-sm ${appPin ? 'left-7' : 'left-1'}`}></div>
                 </button>
             </div>

             {/* Change Password */}
             <div className="space-y-3">
                <label className="block text-sm font-semibold text-slate-700">পাসওয়ার্ড পরিবর্তন</label>
                <div className="flex gap-2">
                    <div className="relative flex-1">
                        <Key size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="password" 
                            placeholder="নতুন পাসওয়ার্ড দিন..." 
                            value={newPassword}
                            onChange={(e) => setNewPassword(e.target.value)}
                            className="w-full pl-9 pr-4 py-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 text-sm font-medium"
                        />
                    </div>
                    <button 
                        onClick={handleChangePassword}
                        disabled={!newPassword || isChangingPass}
                        className="bg-slate-800 text-white px-4 rounded-xl font-bold text-sm hover:bg-slate-900 active:scale-95 transition-all whitespace-nowrap"
                    >
                        {isChangingPass ? <Loader2 size={16} className="animate-spin" /> : 'আপডেট'}
                    </button>
                </div>
             </div>
          </div>
        </div>
      </div>

      {/* Pin Action Modal (Setup or Disable) */}
      {pinAction && (
          <AppLock 
            // If we are disabling, we use 'unlock' mode (verify current pin).
            // If we are setting up, we use 'setup' mode.
            mode={pinAction === 'disable' ? 'unlock' : 'setup'}
            savedPin={pinAction === 'disable' ? appPin : undefined}
            onSuccess={handlePinSuccess}
            onCancel={() => setPinAction(null)}
          />
      )}
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { Project, Client, User, IncomeRecord, UserProfile, Expense } from '../types';
import { supabase, isConfigured } from '../lib/supabase';

interface ToastState {
  message: string;
  type: 'success' | 'error';
}

interface AppContextType {
  // Visible Data (Filtered by Selected User if Admin)
  projects: Project[];
  setProjects: React.Dispatch<React.SetStateAction<Project[]>>;
  clients: Client[];
  setClients: React.Dispatch<React.SetStateAction<Client[]>>;
  incomeRecords: IncomeRecord[];
  setIncomeRecords: React.Dispatch<React.SetStateAction<IncomeRecord[]>>;
  expenses: Expense[];
  setExpenses: React.Dispatch<React.SetStateAction<Expense[]>>;

  // Master Data (Contains ALL data for Admin)
  allProjects: Project[];
  allClients: Client[];
  allIncomeRecords: IncomeRecord[];
  allExpenses: Expense[];

  // Profiles Data (For Admin List)
  userProfiles: UserProfile[];

  user: User | null;
  setUser: React.Dispatch<React.SetStateAction<User | null>>;
  loading: boolean;
  refreshData: () => Promise<void>;
  toast: ToastState | null;
  showToast: (message: string, type?: 'success' | 'error') => void;
  hideToast: () => void;
  isAppLocked: boolean;
  setIsAppLocked: React.Dispatch<React.SetStateAction<boolean>>;
  appPin: string | null;
  setAppPin: (pin: string | null) => void;

  // Admin Specific
  adminSelectedUserId: string | null;
  setAdminSelectedUserId: React.Dispatch<React.SetStateAction<string | null>>;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);

  // Visible State (What components see)
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [incomeRecords, setIncomeRecords] = useState<IncomeRecord[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);

  // Master State (All data cache for Admin)
  const [allProjects, setAllProjects] = useState<Project[]>([]);
  const [allClients, setAllClients] = useState<Client[]>([]);
  const [allIncomeRecords, setAllIncomeRecords] = useState<IncomeRecord[]>([]);
  const [allExpenses, setAllExpenses] = useState<Expense[]>([]);

  // User Profiles
  const [userProfiles, setUserProfiles] = useState<UserProfile[]>([]);

  const [loading, setLoading] = useState(true);
  const [toast, setToast] = useState<ToastState | null>(null);

  // App Lock State
  const [isAppLocked, setIsAppLocked] = useState(false);
  const [appPin, setAppPinState] = useState<string | null>(null);

  // Admin Selection State
  const [adminSelectedUserId, setAdminSelectedUserId] = useState<string | null>(null);

  // Performance optimization: Prevent multiple simultaneous refreshes
  const isFetchingRef = useRef(false);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'error') => {
    setToast({ message, type });
  }, []);

  const hideToast = useCallback(() => {
    setToast(null);
  }, []);

  const setAppPin = (pin: string | null) => {
    if (pin) {
        localStorage.setItem('manage_me_pin', pin);
    } else {
        localStorage.removeItem('manage_me_pin');
    }
    setAppPinState(pin);
  };

  const refreshData = async () => {
    if (!user || !isConfigured) return;

    // If already fetching, ignore this request to save bandwidth
    if (isFetchingRef.current) return;
    isFetchingRef.current = true;

    try {
      const isAdmin = user.role === 'admin';

      // Base queries - fetch everything initially
      let projQuery = supabase.from('projects').select('*');
      let clientQuery = supabase.from('clients').select('*');
      let incomeQuery = supabase.from('income_records').select('*');
      let expenseQuery = supabase.from('expenses').select('*');

      // If NOT admin, filter at DB level for efficiency/security
      if (!isAdmin) {
        projQuery = projQuery.eq('userid', user.id);
        clientQuery = clientQuery.eq('userid', user.id);
        incomeQuery = incomeQuery.eq('userid', user.id);
        expenseQuery = expenseQuery.eq('userid', user.id);
      }

      const [projRes, clientRes, incomeRes, expenseRes] = await Promise.all([
        projQuery.order('createdat', { ascending: false }),
        clientQuery.order('name', { ascending: true }),
        incomeQuery.order('date', { ascending: false }),
        expenseQuery.order('date', { ascending: false })
      ]);

      if (projRes.error) console.warn(`Project load error: ${projRes.error.message}`);

      const pData = projRes.data as Project[] || [];
      const cData = clientRes.data as Client[] || [];
      const iData = incomeRes.data as IncomeRecord[] || [];
      const eData = expenseRes.data as Expense[] || [];

      if (isAdmin) {
        // Store everything in Master State
        setAllProjects(pData);
        setAllClients(cData);
        setAllIncomeRecords(iData);
        setAllExpenses(eData);

        // Fetch User Profiles for Admin List
        const { data: profiles, error: profError } = await supabase.from('profiles').select('*');
        if (!profError && profiles) {
            setUserProfiles(profiles as UserProfile[]);
        }

        // Filter Visible State based on Selection
        if (adminSelectedUserId) {
            setProjects(pData.filter(p => p.userid === adminSelectedUserId));
            setClients(cData.filter(c => c.userid === adminSelectedUserId));
            setIncomeRecords(iData.filter(i => i.userid === adminSelectedUserId));
            setExpenses(eData.filter(e => e.userid === adminSelectedUserId));
        } else {
            // If no user selected, show NOTHING in the main views (forces selection from list)
            setProjects([]);
            setClients([]);
            setIncomeRecords([]);
            setExpenses([]);
        }
      } else {
        // Normal User: Visible = All fetched
        setProjects(pData);
        setClients(cData);
        setIncomeRecords(iData);
        setExpenses(eData);
      }

    } catch (error: any) {
      showToast(`কানেকশন এরর: ${error.message}`);
    } finally {
      setLoading(false);
      isFetchingRef.current = false;
    }
  };

  // Effect to re-filter data when Admin selection changes without re-fetching
  useEffect(() => {
    if (user?.role === 'admin') {
        if (adminSelectedUserId) {
            setProjects(allProjects.filter(p => p.userid === adminSelectedUserId));
            setClients(allClients.filter(c => c.userid === adminSelectedUserId));
            setIncomeRecords(allIncomeRecords.filter(i => i.userid === adminSelectedUserId));
            setExpenses(allExpenses.filter(e => e.userid === adminSelectedUserId));
        } else {
            setProjects([]);
            setClients([]);
            setIncomeRecords([]);
            setExpenses([]);
        }
    }
  }, [adminSelectedUserId, allProjects, allClients, allIncomeRecords, allExpenses, user]);

  // Helper to sync user state with DB profile
  const syncUserWithProfile = async (sessionUser: any) => {
      if (!sessionUser) return null;

      try {
          const metadata = sessionUser.user_metadata;

          // Fetch fresh profile data from DB (Source of Truth)
          // Using maybeSingle() to handle 0 rows gracefully
          const { data: profile } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', sessionUser.id)
            .maybeSingle();

          // Prioritize DB profile over auth metadata for name/avatar
          return {
              id: sessionUser.id,
              email: sessionUser.email || '',
              name: profile?.name || metadata?.name || 'User',
              phone: metadata?.phone || '',
              occupation: metadata?.occupation || '',
              avatar_url: profile?.avatar_url || metadata?.avatar_url || '',
              language: metadata?.language || 'bn',
              currency: metadata?.currency || '৳',
              role: metadata?.role || 'user'
          };
      } catch (e) {
          console.error("Profile sync error", e);
          // Fallback return
          return {
              id: sessionUser.id,
              email: sessionUser.email || '',
              name: sessionUser.user_metadata?.name || 'User',
              role: 'user',
              language: 'bn',
              currency: '৳',
              avatar_url: ''
          } as User;
      }
  };

  useEffect(() => {
    let mounted = true;

    // Check local storage for PIN
    const savedPin = localStorage.getItem('manage_me_pin');
    if (savedPin) {
        setAppPinState(savedPin);
        setIsAppLocked(true); 
    }

    if (!isConfigured) {
      setLoading(false);
      return;
    }

    const initSession = async () => {
      try {
        // Add timeout to prevent infinite loading if getSession hangs
        const sessionPromise = supabase.auth.getSession();
        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error('Session timeout')), 7000)
        );

        const { data: { session }, error } = await Promise.race([sessionPromise, timeoutPromise]) as any;

        if (error) {
            console.warn("Session Init Warning:", error);
        }

        if (session?.user && mounted) {
          const userData = await syncUserWithProfile(session.user);
          if (mounted) setUser(userData);
        }
      } catch (err) {
        console.error("Session Init Error:", err);
      } finally {
        if (mounted) setLoading(false);
      }
    };

    initSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (session?.user) {
        if (mounted) {
            const userData = await syncUserWithProfile(session.user);
            setUser(userData);
        }
      } else {
        if (mounted) {
            setUser(null);
            setProjects([]);
            setClients([]);
            setIncomeRecords([]);
            setExpenses([]);
            setAllProjects([]);
            setAllClients([]);
            setAllIncomeRecords([]);
            setAllExpenses([]);
            setUserProfiles([]);
            setAdminSelectedUserId(null);
        }
      }
      if (mounted) setLoading(false);
    });

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, [showToast]);

  useEffect(() => {
    if (user) {
      refreshData();
    }
  }, [user]);

  return (
    <AppContext.Provider value={{ 
      projects, setProjects, clients, setClients, 
      incomeRecords, setIncomeRecords, expenses, setExpenses,
      allProjects, allClients, allIncomeRecords, allExpenses,
      userProfiles,
      user, setUser, loading, refreshData,
      toast, showToast, hideToast,
      isAppLocked, setIsAppLocked,
      appPin, setAppPin,
      adminSelectedUserId, setAdminSelectedUserId
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useAppContext = () => {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error('useAppContext must be used within an AppProvider');
  }
  return context;
};

import React, { useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { TrendingUp, Plus, Search, Calendar, DollarSign, X, ReceiptText, Briefcase, CreditCard, AlertCircle, MoreVertical, Pencil, Trash2, Users, Loader2, CalendarDays, Wallet, Clock, Zap, Rocket, Landmark, Banknote, Calculator } from 'lucide-react';
import { useAppContext } from '../context/AppContext';
import { Project, IncomeRecord } from '../types';
import { supabase } from '../lib/supabase';
import { NumericKeypad } from '../components/NumericKeypad';
import { ConfirmModal } from '../components/ConfirmModal';

// Custom Bkash Icon to match the brand logo shape (Origami Bird)
const BkashIcon = ({ size = 16, className = "" }: { size?: number, className?: string }) => (
  <svg 
    xmlns="http://www.w3.org/2000/svg" 
    width={size} 
    height={size} 
    viewBox="0 0 100 100" 
    fill="currentColor"
    className={className}
  >
    {/* Sharp angular path representing the origami bird */}
    <path d="M5 5 L50 45 L95 35 L75 65 L25 95 L35 55 Z" />
  </svg>
);

export const Income: React.FC = () => {
  // Use incomeRecords directly from context (cached data)
  const { projects, incomeRecords, user, showToast, refreshData, adminSelectedUserId } = useAppContext();
  const currency = user?.currency || '৳';

  const [isModalOpen, setModalOpen] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [activePaymentId, setActivePaymentId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [projectSearch, setProjectSearch] = useState('');
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedProjectId, setSelectedProjectId] = useState<string | null>(null);
  const [selectedProjectDue, setSelectedProjectDue] = useState<number>(0);
  const [error, setError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Delete Modal
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [paymentToDelete, setPaymentToDelete] = useState<{id: string, payment: any} | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  // Mobile action menu state
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

  // Keypad State
  const [showKeypad, setShowKeypad] = useState(false);

  // Ref for click outside detection
  const projectInputRef = useRef<HTMLDivElement>(null);

  const [newPayment, setNewPayment] = useState<any>({
    projectName: '',
    clientName: '',
    date: new Date().toISOString().split('T')[0],
    amount: 0,
    method: 'বিকাশ'
  });

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      // Close Action Menu
      if (activeMenuId && !(event.target as Element).closest('.action-menu-container')) {
        setActiveMenuId(null);
      }

      // Close Project Suggestions
      if (projectInputRef.current && !projectInputRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [activeMenuId]);

  const initiateDelete = (id: string, payment: any) => {
    setPaymentToDelete({ id, payment });
    setShowDeleteModal(true);
    setActiveMenuId(null);
  };

  const handleConfirmDelete = async () => {
    if (!user || !paymentToDelete) return;
    setIsDeleting(true);

    try {
      let query = supabase.from('income_records').delete().eq('id', paymentToDelete.id);

      // If not admin, restrict delete to own records
      if (user.role !== 'admin') {
        query = query.eq('userid', user.id);
      }

      const { error: delError } = await query;

      if (delError) throw delError;

      const projectId = paymentToDelete.payment.projectid || paymentToDelete.payment.projectId;
      const targetProj = projects.find(p => p.id === projectId);

      if (targetProj) {
        const newPaid = Math.max(0, targetProj.paidamount - paymentToDelete.payment.amount);
        await supabase.from('projects').update({
          paidamount: newPaid,
          dueamount: targetProj.totalamount - newPaid
        }).eq('id', targetProj.id);
      }

      showToast('পেমেন্ট রেকর্ড ডিলিট করা হয়েছে', 'success');
      await refreshData();
      setShowDeleteModal(false);
    } catch (err: any) {
      showToast(`ভুল: ${err.message}`);
      setShowDeleteModal(false);
    } finally {
      setIsDeleting(false);
      setPaymentToDelete(null);
    }
  };

  const handleOpenAddModal = () => {
    resetForm();
    setIsEditing(false);
    setModalOpen(true);
  };

  const handleOpenEditModal = (payment: any) => {
    setIsEditing(true);
    setActivePaymentId(payment.id);
    setNewPayment({ 
      ...payment,
      projectName: payment.projectname || payment.projectName,
      clientName: payment.clientname || payment.clientName
    });
    setProjectSearch(payment.projectname || payment.projectName || '');
    const pId = payment.projectid || payment.projectId;
    setSelectedProjectId(pId);

    const proj = projects.find(p => p.id === pId);
    if (proj) setSelectedProjectDue(proj.dueamount);

    setModalOpen(true);
    setActiveMenuId(null);
  };

  const safeEval = (val: any) => {
    try {
      // eslint-disable-next-line no-new-func
      return new Function('return ' + (val || '0'))();
    } catch {
      return 0;
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    if (!selectedProjectId || !user) {
      setError('দয়া করে একটি প্রজেক্ট সিলেক্ট করুন।');
      return;
    }

    setIsSubmitting(true);
    const amount = Number(safeEval(newPayment.amount)) || 0;
    const selectedProject = projects.find(p => p.id === selectedProjectId);

    // Use selected user ID if admin is viewing a specific user, otherwise current user ID
    const targetUserId = (user.role === 'admin' && adminSelectedUserId) ? adminSelectedUserId : user.id;

    try {
      if (isEditing && activePaymentId) {
        const oldPayment = incomeRecords.find(p => p.id === activePaymentId);
        const delta = amount - (oldPayment?.amount || 0);

        let query = supabase.from('income_records').update({
          amount,
          date: newPayment.date,
          method: newPayment.method
        }).eq('id', activePaymentId);

        if (user.role !== 'admin') {
            query = query.eq('userid', user.id);
        }

        const { error: updErr } = await query;

        if (updErr) throw updErr;

        if (selectedProject) {
          const newPaid = selectedProject.paidamount + delta;
          await supabase.from('projects').update({
            paidamount: newPaid,
            dueamount: Math.max(0, selectedProject.totalamount - newPaid)
          }).eq('id', selectedProjectId);
        }
        showToast('রেকর্ড আপডেট করা হয়েছে', 'success');
      } else {
        const { error: insErr } = await supabase.from('income_records').insert({
          projectid: selectedProjectId,
          projectname: selectedProject?.name,
          clientname: selectedProject?.clientname,
          amount,
          date: newPayment.date,
          method: newPayment.method,
          userid: targetUserId
        });

        if (insErr) throw insErr;

        if (selectedProject) {
          const newPaid = selectedProject.paidamount + amount;
          await supabase.from('projects').update({
            paidamount: newPaid,
            dueamount: Math.max(0, selectedProject.totalamount - newPaid)
          }).eq('id', selectedProjectId);
        }
        showToast('নতুন পেমেন্ট রেকর্ড করা হয়েছে', 'success');
      }

      setModalOpen(false);
      await refreshData();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const resetForm = () => {
    setNewPayment({ projectName: '', clientName: '', date: new Date().toISOString().split('T')[0], amount: 0, method: 'বিকাশ' });
    setProjectSearch('');
    setSelectedProjectId(null);
    setSelectedProjectDue(0);
    setError(null);
    setActivePaymentId(null);
  };

  const filteredPayments = incomeRecords.filter(p => 
    (p.projectname || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
    (p.clientname || '').toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Filter: Match name AND ensure Due Amount > 0
  const projectSuggestions = projects.filter(p => 
    (p.name || '').toLowerCase().includes(projectSearch.toLowerCase()) && 
    p.dueamount > 0
  );

  const handleSelectProject = (project: Project) => {
    setProjectSearch(project.name);
    setNewPayment({ ...newPayment, projectName: project.name, clientName: project.clientname });
    setSelectedProjectId(project.id);
    setSelectedProjectDue(project.dueamount);
    setShowSuggestions(false);
    setError(null);
  };

  const totalIncome = incomeRecords.reduce((acc, curr) => acc + curr.amount, 0);

  const getPaymentMethodStyle = (method: string) => {
    switch(method) {
      case 'বিকাশ': 
        return { 
          style: 'bg-pink-50 text-pink-600', 
          icon: <BkashIcon size={12} /> 
        };
      case 'নগদ': 
        return { 
          style: 'bg-orange-50 text-orange-600', 
          icon: <Zap size={10} /> 
        };
      case 'রকেট': 
        return { 
          style: 'bg-purple-50 text-purple-600', 
          icon: <Rocket size={10} /> 
        };
      case 'ব্যাংক': 
        return { 
          style: 'bg-indigo-50 text-indigo-600', 
          icon: <Landmark size={10} /> 
        };
      default: 
        return { 
          style: 'bg-emerald-50 text-emerald-600', 
          icon: <Banknote size={10} /> 
        };
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold text-slate-800">
            {user?.role === 'admin' ? (adminSelectedUserId ? 'ইউজার আয়' : 'আয় (অ্যাডমিন ভিউ)') : 'আয় (পেমেন্ট)'}
          </h1>
          <p className="text-xs text-slate-500 font-medium">মোট আয়: <span className="text-emerald-600 font-bold">{currency} {totalIncome.toLocaleString('bn-BD')}</span></p>
        </div>
        <button 
          onClick={handleOpenAddModal}
          className="bg-emerald-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-lg shadow-emerald-200 active:scale-90 transition-transform"
        >
          <Plus size={24} />
        </button>
      </div>

      <div className="bg-white px-4 py-2.5 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-2">
        <Search size={18} className="text-slate-400" />
        <input 
          type="text" 
          placeholder="পেমেন্ট খুঁজুন..." 
          className="w-full bg-transparent outline-none text-sm font-bold text-slate-800 placeholder:text-slate-400" 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="space-y-3 pb-20">
        {filteredPayments.length === 0 ? (
          <div className="py-20 text-center text-slate-400">
            <ReceiptText size={48} className="mx-auto mb-4 opacity-20" />
            <p className="text-sm font-medium">কোনো পেমেন্ট নেই</p>
          </div>
        ) : (
          filteredPayments.map((payment) => {
            const { style, icon } = getPaymentMethodStyle(payment.method);
            return (
              <div key={payment.id} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm relative animate-in slide-in-from-bottom-2 duration-300">
                <div className="flex justify-between items-start mb-2">
                  <div className="flex items-center gap-3">
                     <div className="w-10 h-10 rounded-xl bg-emerald-50 text-emerald-600 flex items-center justify-center font-bold">
                       <DollarSign size={20} />
                     </div>
                     <div>
                       <h3 className="font-bold text-slate-800 text-sm">{payment.projectname}</h3>
                       <p className="text-xs text-slate-500 font-medium">{payment.clientname}</p>
                     </div>
                  </div>

                  <div className="relative action-menu-container">
                      <button 
                        onClick={(e) => {
                           e.stopPropagation();
                           setActiveMenuId(activeMenuId === payment.id ? null : payment.id);
                        }}
                        className={`p-2 -mr-2 rounded-full transition-colors ${activeMenuId === payment.id ? 'bg-emerald-50 text-emerald-600' : 'text-slate-300 hover:text-emerald-600 active:bg-slate-50'}`}
                      >
                        <MoreVertical size={20} />
                      </button>

                      {activeMenuId === payment.id && (
                         <div className="absolute right-0 top-full mt-1 w-36 bg-white rounded-xl shadow-xl border border-slate-100 z-20 flex flex-col py-1.5 animate-in fade-in zoom-in-95 duration-200 origin-top-right">
                              <button 
                                  onClick={(e) => { e.stopPropagation(); handleOpenEditModal(payment); }}
                                  className="w-full px-4 py-2.5 text-left text-xs font-bold text-slate-600 hover:bg-slate-50 hover:text-emerald-600 flex items-center gap-2 transition-colors"
                              >
                                  <Pencil size={14} /> এডিট
                              </button>
                              <div className="h-px bg-slate-50 w-full my-0.5"></div>
                              <button 
                                  onClick={(e) => { e.stopPropagation(); initiateDelete(payment.id, payment); }}
                                  className="w-full px-4 py-2.5 text-left text-xs font-bold text-rose-500 hover:bg-rose-50 flex items-center gap-2 transition-colors"
                              >
                                   <Trash2 size={14} /> ডিলিট
                              </button>
                          </div>
                      )}
                  </div>
                </div>

                <div className="flex justify-between items-end border-t border-slate-50 pt-3 mt-1">
                  <div>
                     <p className="text-[10px] text-slate-400 font-bold uppercase mb-0.5">তারিখ</p>
                     <p className="text-xs font-bold text-slate-600 flex items-center gap-1">
                       <Calendar size={12} /> {payment.date}
                     </p>
                  </div>
                  <div className="text-right">
                     <span className={`text-[10px] px-2 py-0.5 rounded font-bold mb-1 inline-flex items-center gap-1 ${style}`}>
                       {icon}
                       {payment.method}
                     </span>
                     <p className="text-lg font-black text-emerald-600">{currency} {payment.amount.toLocaleString('bn-BD')}</p>
                  </div>
                </div>
              </div>
            );
          })
        )}
      </div>

      <ConfirmModal 
        isOpen={showDeleteModal}
        onClose={() => setShowDeleteModal(false)}
        onConfirm={handleConfirmDelete}
        title="পেমেন্ট ডিলিট"
        message="আপনি কি নিশ্চিত? এটি ডিলিট করলে প্রজেক্টের বকেয়া আবার বেড়ে যাবে।"
        isProcessing={isDeleting}
      />

      {isModalOpen && createPortal(
        <div className="fixed inset-0 z-[1000] bg-white flex flex-col h-[100dvh] animate-in fade-in duration-200">
            <div className="px-4 py-3 border-b border-slate-100 flex items-center justify-between bg-white shrink-0">
              <h2 className="text-base font-bold text-slate-800">{isEditing ? 'এডিট পেমেন্ট' : 'নতুন পেমেন্ট'}</h2>
              <button disabled={isSubmitting} onClick={() => setModalOpen(false)} className="p-2 bg-slate-50 rounded-full text-slate-500 hover:bg-slate-100 transition-colors">
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto">
                <form onSubmit={handleSubmit} className="px-4 pt-3 pb-24 space-y-4">
                  {error && <div className="p-3 bg-rose-50 text-rose-600 text-xs rounded-xl font-bold flex items-center gap-2"><AlertCircle size={14} /> {error}</div>}

                  <div className="relative" ref={projectInputRef}>
                    <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">প্রজেক্ট</label>
                    <input 
                        type="text" 
                        value={projectSearch} 
                        onFocus={() => setShowSuggestions(true)} 
                        onChange={e => {setProjectSearch(e.target.value); setShowSuggestions(true);}} 
                        className="w-full px-3 py-3 bg-slate-50 border border-slate-200 rounded-xl font-bold text-slate-800 focus:ring-2 focus:ring-emerald-500 outline-none text-sm" 
                        placeholder="প্রজেক্ট খুঁজুন..." 
                    />
                    {showSuggestions && projectSuggestions.length > 0 && (
                      <div className="absolute top-full mt-1 w-full bg-white border border-slate-100 rounded-xl shadow-2xl max-h-40 overflow-y-auto z-[60]">
                        {projectSuggestions.map(p => (
                          <div key={p.id} onClick={() => handleSelectProject(p)} className="px-4 py-3 border-b border-slate-50 hover:bg-emerald-50 cursor-pointer transition-colors">
                            <div className="font-bold text-sm text-slate-800">{p.name}</div>
                            <div className="text-xs text-slate-500">{p.clientname}</div>
                          </div>
                        ))}
                      </div>
                    )}
                    {selectedProjectId && (
                      <div className="flex justify-end mt-2 animate-in slide-in-from-top-1">
                        <div className="text-xs font-bold text-slate-600 bg-slate-50 border border-slate-200 px-2 py-1 rounded-lg">
                           বকেয়া: <span className="text-rose-600">{currency} {selectedProjectDue.toLocaleString('bn-BD')}</span>
                        </div>
                      </div>
                    )}
                  </div>

                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">পরিমাণ ({currency})</label>
                    <div 
                      onClick={() => setShowKeypad(true)}
                      className="keypad-trigger w-full px-3 py-3 bg-slate-50 border border-slate-200 rounded-xl font-black text-xl text-emerald-600 active:bg-slate-100 transition-colors flex items-center justify-between cursor-pointer"
                    >
                       <span>{newPayment.amount || 0}</span>
                       <Calculator size={18} className="text-slate-400" />
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-3">
                    <div>
                      <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">তারিখ</label>
                      <input required type="date" value={newPayment.date} onChange={e => setNewPayment({...newPayment, date: e.target.value})} className="w-full px-3 py-3 bg-white border border-slate-200 rounded-xl font-bold text-sm text-slate-800 outline-none focus:ring-2 focus:ring-emerald-500" />
                    </div>
                    <div>
                      <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">পদ্ধতি</label>
                      <select value={newPayment.method} onChange={e => setNewPayment({...newPayment, method: e.target.value})} className="w-full px-3 py-3 bg-white border border-slate-200 rounded-xl font-bold text-sm text-slate-800 outline-none focus:ring-2 focus:ring-emerald-500">
                        <option value="বিকাশ">বিকাশ</option>
                        <option value="নগদ">নগদ</option>
                        <option value="রকেট">রকেট</option>
                        <option value="ব্যাংক">ব্যাংক</option>
                        <option value="নগদ (ক্যাশ)">ক্যাশ</option>
                      </select>
                    </div>
                  </div>

                  <button type="submit" disabled={isSubmitting} className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-bold text-base shadow-lg shadow-emerald-200 active:scale-95 transition-transform flex items-center justify-center gap-2 mt-4">
                    {isSubmitting ? <Loader2 className="animate-spin" /> : <Wallet />}
                    সেভ করুন
                  </button>
                </form>
            </div>

            <NumericKeypad 
              isOpen={showKeypad}
              onClose={() => setShowKeypad(false)}
              onValueChange={(val) => setNewPayment({...newPayment, amount: val})}
              initialValue={newPayment.amount}
              title="পেমেন্ট পরিমাণ"
            />
        </div>,
        document.body
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { Receipt, Plus, Search, Tag, X, ShoppingCart, Loader2, Trash2, MoreVertical, Pencil, Calculator } from 'lucide-react';
import { EXPENSE_CATEGORY_LABELS } from '../constants';
import { useAppContext } from '../context/AppContext';
import { supabase } from '../lib/supabase';
import { NumericKeypad } from '../components/NumericKeypad';
import { ConfirmModal } from '../components/ConfirmModal';

export const Expenses: React.FC = () => {
  // Use cached expenses from AppContext
  const { user, showToast, adminSelectedUserId, expenses, setExpenses, refreshData } = useAppContext();
  const [isModalOpen, setModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // New states for Edit/Delete menu
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [activeExpenseId, setActiveExpenseId] = useState<string | null>(null);

  // Delete Modal
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [expenseToDelete, setExpenseToDelete] = useState<{id: string, userid: string} | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  // Keypad State
  const [showKeypad, setShowKeypad] = useState(false);

  // Category input suggestion states
  const [showCategorySuggestions, setShowCategorySuggestions] = useState(false);
  const categoryInputRef = useRef<HTMLDivElement>(null);

  const [newExpense, setNewExpense] = useState<any>({
    category: '',
    date: new Date().toISOString().split('T')[0],
    amount: 0,
    notes: ''
  });

  // Removed fetchExpenses() logic because it is now handled globally in AppContext

  // Click outside to close suggestions and menus
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      // Close Category Suggestions
      if (categoryInputRef.current && !categoryInputRef.current.contains(event.target as Node)) {
        setShowCategorySuggestions(false);
      }

      // Close Action Menu
      if (activeMenuId && !(event.target as Element).closest('.action-menu-container')) {
        setActiveMenuId(null);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [activeMenuId]);

  // Derive unique categories from existing expenses for suggestions
  const uniqueCategories = Array.from(new Set(expenses.map((e: any) => e.category as string).filter(Boolean))) as string[];

  const allSuggestions: string[] = uniqueCategories;

  const filteredSuggestions = allSuggestions.filter(c => 
    (EXPENSE_CATEGORY_LABELS[c] || c).toLowerCase().includes((newExpense.category || '').toLowerCase())
  );

  const handleSelectCategory = (category: string) => {
    // Use localized label if available, otherwise use the category key itself
    const label = EXPENSE_CATEGORY_LABELS[category] || category;
    setNewExpense({ ...newExpense, category: label });
    setShowCategorySuggestions(false);
  };

  const handleOpenAddModal = () => {
    setIsEditing(false);
    setActiveExpenseId(null);
    setNewExpense({ category: '', date: new Date().toISOString().split('T')[0], amount: 0, notes: '' });
    setModalOpen(true);
  };

  const handleOpenEditModal = (expense: any) => {
    setIsEditing(true);
    setActiveExpenseId(expense.id);
    setNewExpense({
      // Use localized label for input field when editing
      category: EXPENSE_CATEGORY_LABELS[expense.category] || expense.category,
      date: expense.date,
      amount: expense.amount,
      notes: expense.notes
    });
    setModalOpen(true);
    setActiveMenuId(null);
  };

  const safeEval = (val: any) => {
    try {
      // eslint-disable-next-line no-new-func
      return new Function('return ' + (val || '0'))();
    } catch {
      return 0;
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newExpense.amount || !newExpense.category || !user) return;

    setIsSubmitting(true);

    // Evaluate possible math expressions
    const parsedAmount = Number(safeEval(newExpense.amount)) || 0;

    // Use selected user ID if admin is viewing a specific user, otherwise current user ID
    const targetUserId = (user.role === 'admin' && adminSelectedUserId) ? adminSelectedUserId : user.id;

    try {
      if (isEditing && activeExpenseId) {
        let query = supabase.from('expenses').update({
          category: newExpense.category,
          amount: parsedAmount,
          date: newExpense.date,
          notes: newExpense.notes
        }).eq('id', activeExpenseId);

        // If not admin, restrict to own records
        if (user.role !== 'admin') {
            query = query.eq('userid', user.id);
        }

        const { error } = await query;
        if (error) throw error;
        showToast('খরচ আপডেট হয়েছে', 'success');
      } else {
        // Insert new expense
        const { error } = await supabase.from('expenses').insert({
          category: newExpense.category,
          amount: parsedAmount,
          date: newExpense.date,
          notes: newExpense.notes,
          userid: targetUserId
        });

        if (error) throw error;
        showToast('খরচ সফলভাবে সেভ হয়েছে', 'success');
      }

      setModalOpen(false);
      await refreshData(); // Refresh global context
      if (!isEditing) {
        setNewExpense({ category: '', date: new Date().toISOString().split('T')[0], amount: 0, notes: '' });
      }
    } catch (error: any) {
      showToast(`সমস্যা: ${error.message}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  const initiateDelete = (id: string, userid: string) => {
    setExpenseToDelete({id, userid});
    setShowDeleteModal(true);
    setActiveMenuId(null);
  };

  const handleConfirmDelete = async () => {
    if (!expenseToDelete) return;
    setIsDeleting(true);
    try {
      let query = supabase.from('expenses').delete().eq('id', expenseToDelete.id);

      // If not admin, restrict to own records
      if (user?.role !== 'admin') {
          query = query.eq('userid', user?.id);
      }

      const { error } = await query;
      if (error) showToast(error.message);
      else {
        showToast('খরচ মুছে ফেলা হয়েছে', 'success');
        await refreshData(); // Refresh global context
      }
      setShowDeleteModal(false);
    } catch(err: any) {
      showToast(err.message);
      setShowDeleteModal(false);
    } finally {
      setIsDeleting(false);
      setExpenseToDelete(null);
    }
  };

  const filteredExpenses = expenses.filter(e => 
    (e.notes || '').toLowerCase().includes(searchTerm.toLowerCase()) || 
    (e.category || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
    (EXPENSE_CATEGORY_LABELS[e.category] || '').toLowerCase().includes(searchTerm.toLowerCase())
  );

  const totalExpenseAll = expenses.reduce((acc, curr) => acc + curr.amount, 0);

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold text-slate-800">
             {user?.role === 'admin' ? (adminSelectedUserId ? 'ইউজার খরচ' : 'খরচসমূহ (অ্যাডমিন ভিউ)') : 'খরচসমূহ'}
          </h1>
          <p className="text-xs text-slate-500 font-medium">মোট খরচ: <span className="text-rose-600 font-bold">{user?.currency || '৳'} {totalExpenseAll.toLocaleString('bn-BD')}</span></p>
        </div>
        <button 
          onClick={handleOpenAddModal}
          className="bg-rose-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-lg shadow-rose-200 active:scale-90 transition-transform"
        >
          <Plus size={24} />
        </button>
      </div>

      <div className="bg-white px-4 py-2.5 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-2">
        <Search size={18} className="text-slate-400" />
        <input 
          type="text" 
          placeholder="বিবরণ বা ক্যাটাগরি দিয়ে খুঁজুন..." 
          className="w-full bg-transparent outline-none text-sm font-bold text-slate-800 placeholder:text-slate-400" 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="space-y-3 pb-20">
        {filteredExpenses.length === 0 ? (
          <div className="py-20 text-center text-slate-400">
            <ShoppingCart size={48} className="mx-auto mb-4 opacity-20" />
            <p className="text-sm font-medium">কোনো খরচ নেই</p>
          </div>
        ) : (
          filteredExpenses.map((expense) => (
            <div key={expense.id} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between animate-in slide-in-from-bottom-2 duration-300">
              <div className="flex items-center gap-3 overflow-hidden">
                <div className="w-10 h-10 rounded-xl bg-rose-50 text-rose-600 flex items-center justify-center">
                  <Tag size={18} />
                </div>
                <div className="min-w-0">
                  <h3 className="font-bold text-slate-800 text-sm truncate">{expense.notes}</h3>
                  <p className="text-xs text-slate-500 font-medium">{EXPENSE_CATEGORY_LABELS[expense.category] || expense.category} • {expense.date}</p>
                </div>
              </div>
              <div className="flex items-center gap-2 pl-2">
                <span className="font-black text-rose-600 text-base mr-1">{user?.currency || '৳'} {expense.amount.toLocaleString('bn-BD')}</span>

                {/* Action Menu */}
                <div className="relative action-menu-container">
                    <button 
                      onClick={(e) => {
                          e.stopPropagation();
                          setActiveMenuId(activeMenuId === expense.id ? null : expense.id);
                      }}
                      className={`p-2 -mr-2 rounded-full transition-colors ${activeMenuId === expense.id ? 'bg-rose-50 text-rose-600' : 'text-slate-300 hover:text-rose-600 active:bg-slate-50'}`}
                    >
                      <MoreVertical size={20} />
                    </button>

                    {activeMenuId === expense.id && (
                        <div className="absolute right-0 top-full mt-1 w-36 bg-white rounded-xl shadow-xl border border-slate-100 z-20 flex flex-col py-1.5 animate-in fade-in zoom-in-95 duration-200 origin-top-right">
                            <button 
                                onClick={(e) => { e.stopPropagation(); handleOpenEditModal(expense); }}
                                className="w-full px-4 py-2.5 text-left text-xs font-bold text-slate-600 hover:bg-slate-50 hover:text-indigo-600 flex items-center gap-2 transition-colors"
                            >
                                <Pencil size={14} /> এডিট
                            </button>
                            <div className="h-px bg-slate-50 w-full my-0.5"></div>
                            <button 
                                onClick={(e) => { e.stopPropagation(); initiateDelete(expense.id, expense.userid); }}
                                className="w-full px-4 py-2.5 text-left text-xs font-bold text-rose-500 hover:bg-rose-50 flex items-center gap-2 transition-colors"
                            >
                                <Trash2 size={14} /> ডিলিট
                            </button>
                        </div>
                    )}
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      <ConfirmModal 
        isOpen={showDeleteModal}
        onClose={() => setShowDeleteModal(false)}
        onConfirm={handleConfirmDelete}
        title="খরচ ডিলিট"
        message="আপনি কি এই খরচের রেকর্ডটি মুছে ফেলতে চান?"
        isProcessing={isDeleting}
      />

      {isModalOpen && createPortal(
        <div className="fixed inset-0 z-[1000] bg-white flex flex-col h-[100dvh] animate-in fade-in duration-200">
            <div className="px-4 py-3 border-b border-slate-100 flex items-center justify-between bg-white shrink-0">
              <h2 className="text-base font-bold text-slate-800">
                {isEditing ? 'খরচ এডিট' : 'নতুন খরচ'}
              </h2>
              <button disabled={isSubmitting} onClick={() => setModalOpen(false)} className="p-2 bg-slate-50 rounded-full text-slate-500 hover:bg-slate-100 transition-colors">
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto">
                <form onSubmit={handleSubmit} className="px-4 pt-3 pb-24 space-y-4">

                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">বিবরণ</label>
                    <input required type="text" value={newExpense.notes} onChange={e => setNewExpense({...newExpense, notes: e.target.value})} className="w-full px-3 py-3 bg-slate-50 border border-slate-200 rounded-xl font-bold text-slate-800 focus:ring-2 focus:ring-rose-500 outline-none text-sm" placeholder="কিসের জন্য খরচ?" />
                  </div>

                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">
                        পরিমাণ ({user?.currency})
                    </label>
                    <div 
                      onClick={() => setShowKeypad(true)}
                      className="keypad-trigger w-full px-3 py-3 bg-slate-50 border border-slate-200 rounded-xl font-black text-xl text-rose-600 active:bg-slate-100 transition-colors flex items-center justify-between cursor-pointer"
                    >
                       <span>{newExpense.amount || 0}</span>
                       <Calculator size={18} className="text-slate-400" />
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-3">
                    <div>
                      <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">তারিখ</label>
                      <input required type="date" value={newExpense.date} onChange={e => setNewExpense({...newExpense, date: e.target.value})} className="w-full px-3 py-3 bg-white border border-slate-200 rounded-xl font-bold text-sm text-slate-800 outline-none focus:ring-2 focus:ring-rose-500" />
                    </div>

                    {/* Category Input with Suggestions */}
                    <div className="relative" ref={categoryInputRef}>
                      <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">ক্যাটাগরি</label>
                      <input 
                        type="text"
                        value={newExpense.category}
                        onFocus={() => setShowCategorySuggestions(true)}
                        onChange={e => {
                          setNewExpense({...newExpense, category: e.target.value});
                          setShowCategorySuggestions(true);
                        }}
                        className="w-full px-3 py-3 bg-white border border-slate-200 rounded-xl font-bold text-sm text-slate-800 outline-none focus:ring-2 focus:ring-rose-500"
                        placeholder="ক্যাটাগরি লিখুন..."
                        required
                      />

                      {showCategorySuggestions && (newExpense.category || filteredSuggestions.length > 0) && (
                        <div className="absolute top-full right-0 left-0 mt-1 w-full bg-white border border-slate-100 rounded-xl shadow-2xl max-h-40 overflow-y-auto z-[60]">
                          {filteredSuggestions.map((cat, idx) => (
                            <div key={idx} onClick={() => handleSelectCategory(cat)} className="px-4 py-3 border-b border-slate-50 hover:bg-rose-50 font-medium text-sm cursor-pointer transition-colors text-slate-700">
                              {EXPENSE_CATEGORY_LABELS[cat] || cat}
                            </div>
                          ))}
                          {!filteredSuggestions.some(c => (EXPENSE_CATEGORY_LABELS[c] || c).toLowerCase() === (newExpense.category || '').toLowerCase()) && newExpense.category && (
                            <div className="px-4 py-3 bg-emerald-50 text-emerald-700 text-xs font-bold border-t">
                              + নতুন ক্যাটাগরি হিসেবে যোগ হবে
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  </div>

                  <button type="submit" disabled={isSubmitting} className="w-full bg-rose-600 text-white py-4 rounded-2xl font-bold text-base shadow-lg shadow-rose-200 active:scale-95 transition-transform flex items-center justify-center gap-2 mt-4">
                    {isSubmitting ? <Loader2 className="animate-spin" /> : <Receipt />}
                    খরচ সেভ করুন
                  </button>
                </form>
            </div>

            <NumericKeypad 
              isOpen={showKeypad}
              onClose={() => setShowKeypad(false)}
              onValueChange={(val) => setNewExpense({...newExpense, amount: val})}
              initialValue={newExpense.amount}
              title="খরচের পরিমাণ"
            />
        </div>,
        document.body
      )}
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { User as UserIcon, Bell, Shield, Palette, Globe, Save, CheckCircle2, Loader2, Camera, UploadCloud, AlertCircle, Lock, Key } from 'lucide-react';
import { APP_NAME } from '../constants';
import { useAppContext } from '../context/AppContext';
import { supabase } from '../lib/supabase';
import { AppLock } from '../components/AppLock';

export const Settings: React.FC = () => {
  const { user, setUser, showToast, appPin, setAppPin } = useAppContext();
  const [formData, setFormData] = useState({
    name: user?.name || '',
    email: user?.email || '',
    phone: user?.phone || '',
    occupation: user?.occupation || '',
    language: user?.language || 'bn',
    currency: user?.currency || '৳'
  });
  const [isSaving, setIsSaving] = useState(false);
  const [isUploading, setIsUploading] = useState(false);

  // Security State
  const [newPassword, setNewPassword] = useState('');
  const [isChangingPass, setIsChangingPass] = useState(false);

  // 'setup' means setting a new pin, 'disable' means verifying pin to turn it off
  const [pinAction, setPinAction] = useState<'setup' | 'disable' | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0 || !user) return;

    const file = e.target.files[0];
    const fileExt = file.name.split('.').pop();
    const fileName = `${user.id}/${Date.now()}.${fileExt}`;
    const filePath = fileName;

    setIsUploading(true);

    try {
      const { error: uploadError } = await supabase.storage
        .from('avatars')
        .upload(filePath, file, { upsert: true });

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from('avatars')
        .getPublicUrl(filePath);

      // Update Auth Metadata
      const { error: authError } = await supabase.auth.updateUser({
        data: { avatar_url: publicUrl }
      });

      if (authError) throw authError;

      // Update Profiles Table (Source of Truth)
      const { error: profileError } = await supabase
        .from('profiles')
        .update({ avatar_url: publicUrl })
        .eq('id', user.id);

      if (profileError) console.error("Profile update failed", profileError);

      setUser(prev => prev ? ({ ...prev, avatar_url: publicUrl }) : null);
      showToast('প্রোফাইল ছবি আপডেট হয়েছে!', 'success');

    } catch (error: any) {
      console.error(error);
      showToast('ছবি আপলোড করতে সমস্যা হয়েছে', 'error');
    } finally {
      setIsUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleSave = async () => {
    if (!user) return;
    setIsSaving(true);

    // Store previous state for rollback
    const previousUser = user;

    // OPTIMISTIC UPDATE: Update UI immediately so user feels it's done
    setUser({
        ...user,
        name: formData.name,
        phone: formData.phone,
        occupation: formData.occupation,
        language: formData.language as 'bn' | 'en',
        currency: formData.currency
    });

    try {
      // Helper for timeouts
      const withTimeout = (promise: Promise<any>, ms: number, errorMsg: string) => {
          return Promise.race([
              promise,
              new Promise((_, reject) => setTimeout(() => reject(new Error(errorMsg)), ms))
          ]);
      };

      // 1. Try Refresh Session (Short timeout, ignore if fails)
      try {
        await withTimeout(supabase.auth.refreshSession(), 5000, 'Refresh Timeout');
      } catch (e) {
        console.warn("Session refresh skipped due to timeout/error");
      }

      // 2. Update Auth Metadata (15s timeout)
      // This is the actual cloud save
      const { error } = await withTimeout(
        supabase.auth.updateUser({
            data: {
            name: formData.name,
            phone: formData.phone,
            occupation: formData.occupation,
            language: formData.language,
            currency: formData.currency
            }
        }), 
        15000, 
        'Update Timeout'
      );

      if (error) throw error;

      // 3. Update Profiles Table (Best effort, non-blocking)
      supabase.from('profiles')
        .update({ name: formData.name })
        .eq('id', user.id)
        .then(({ error }) => {
            if (error) console.warn("Profile table sync warning", error);
        });

      showToast('সেটিংস সফলভাবে সেভ হয়েছে', 'success');
    } catch (err: any) {
      console.error("Save Error:", err);
      // Rollback on critical failure
      setUser(previousUser);
