                         <Users size={10} /> {p.clientname}
                      </p>
                   </div>
                </div>

                <div className="text-right whitespace-nowrap">
                  <p className="font-bold text-slate-800 text-sm">{currency} {p.totalamount.toLocaleString('en-US')}</p>
